import React, { useState, useRef } from "react";
import { motion, AnimatePresence, useInView } from "framer-motion";
import { List } from "../ui/List";
import { IconMinimaze, IconPlus } from "../../assets/icons/interfaceIcons2";

export const FAQSection = () => {
  const sectionRef = useRef(null);
  const isInView = useInView(sectionRef, { once: true });
  const [openIndex, setOpenIndex] = useState(null);

  const faqData = [
    {
      id: 1,
      question: "Can you cancel a project at any time?",
      answer:
        "Yes, you can cancel your project anytime. Please contact our support team for assistance.",
    },
    {
      id: 2,
      question: "How often do we work without prepayment?",
      answer:
        "We usually require prepayment, but special agreements can be discussed with our team.",
    },
    {
      id: 3,
      question: "How to contact technical support?",
      answer:
        "You can contact our support team via email or through the contact form on our website.",
    },
  ];

  const toggleFAQ = (index) => {
    setOpenIndex(openIndex === index ? null : index);
  };

  return (
    <section ref={sectionRef} className="bg-gray-200 py-16 lg:py-24 w-full">

      {/* Title */}
      <motion.h2
        initial={{ opacity: 0, y: 40 }}
        animate={isInView ? { opacity: 1, y: 0 } : {}}
        transition={{ duration: 0.8 }}
        className="text-3xl sm:text-4xl md:text-5xl lg:text-6xl font-semibold px-6 md:px-16 lg:px-32 mb-16"
      >
        Frequently asked questions
      </motion.h2>

      {/* FAQ List */}
      <motion.div
        initial="hidden"
        animate={isInView ? "show" : "hidden"}
        variants={{
          hidden: {},
          show: { transition: { staggerChildren: 0.08 } },
        }}
        className="flex flex-col w-full border-t border-gray-300"
      >
        <List
          data={faqData}
          uniqueKey="id"
          className="flex flex-col w-full"
          render={(item, index) => (
            <motion.div
              key={item.id}
              variants={{
                hidden: { opacity: 0, y: 30 },
                show: { opacity: 1, y: 0 },
              }}
              transition={{ duration: 0.6 }}
              className="group border-b border-gray-300 hover:bg-white transition-all"
            >

              {/* Question Row */}
              <div
                onClick={() => toggleFAQ(index)}
                className="flex items-center justify-between px-6 md:px-16 lg:px-32 py-6 md:py-8 lg:py-10 cursor-pointer"
              >
                <h3 className="text-lg sm:text-xl md:text-2xl lg:text-3xl xl:text-4xl font-medium pr-6 max-w-[900px]">
                  {item.question}
                </h3>

                {/* Icon */}
                <motion.div
                  animate={{ rotate: openIndex === index ? 180 : 0 }}
                  transition={{ duration: 0.3 }}
                  className="flex-shrink-0 w-12 h-12 md:w-14 md:h-14 lg:w-16 lg:h-16 flex items-center justify-center rounded-full bg-gray-100 group-hover:bg-black group-hover:text-white transition-all"
                >
                  {openIndex === index ? (
                    <IconMinimaze size="24" />
                  ) : (
                    <IconPlus size="24" />
                  )}
                </motion.div>
              </div>

              {/* Answer */}
              <AnimatePresence initial={false}>
                {openIndex === index && (
                  <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: "auto", opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    transition={{ duration: 0.4 }}
                    className="overflow-hidden px-6 md:px-16 lg:px-32"
                  >
                    <p className="text-gray-600 text-sm md:text-xl max-w-2xl pb-6 md:pb-8 lg:pb-10">
                      {item.answer}
                    </p>
                  </motion.div>
                )}
              </AnimatePresence>

            </motion.div>
          )}
        />
      </motion.div>
    </section>
  );
};

import React, { useEffect, useRef, useState } from "react";
import { gsap } from "gsap";
import Button from "../ui/button/Button";
import { Link } from "react-router-dom";

export const Hero = () => {
  const bgRef = useRef();
  const titleRef = useRef();
  const textRef = useRef();
  const buttonRef = useRef();

  const [currentSlide, setCurrentSlide] = useState(0);

  const slides = [
    {
      title: "Homart Architects & Builders",
      text: "We specialize in architectural design, construction, and interior solutions. Our mission is to create modern, functional, and beautiful spaces.",
      image: "/imgs/hero-bg.webp",
    },
    {
      title: "Building Construction",
      text: "Professional residential and commercial construction services with high-quality materials.",
      image:
        "https://i.pinimg.com/736x/93/10/9a/93109afa8ea24d0e0145750a40f13fca.jpg",
    },
    {
      title: "Interior Design",
      text: "Elegant and functional interior design solutions that transform your living spaces beautifully.",
      image:
        "https://i.pinimg.com/1200x/8f/96/c9/8f96c9e18f4dc0aaf6f9ab08b2a996ed.jpg",
    },
    {
      title: "HADD Division",
      text: "Approvals, permits, and technical drawings handled professionally.",
      image:
        "https://i.pinimg.com/736x/41/b0/44/41b044cb9856e20792bf124b08d974d4.jpg",
    },
  ];

  /* Auto Slide */
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % slides.length);
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  /* Animation */
  useEffect(() => {
    const ctx = gsap.context(() => {
      gsap.fromTo(
        titleRef.current,
        { y: 40, opacity: 0 },
        { y: 0, opacity: 1, duration: 1 },
      );

      gsap.fromTo(
        textRef.current,
        { y: 40, opacity: 0 },
        { y: 0, opacity: 1, duration: 0.8, delay: 0.2 },
      );

      gsap.fromTo(
        buttonRef.current,
        { y: 40, opacity: 0 },
        { y: 0, opacity: 1, duration: 0.6, delay: 0.4 },
      );

      gsap.to(bgRef.current, {
        scale: 1.1,
        duration: 18,
        repeat: -1,
        yoyo: true,
        ease: "none",
      });
    });

    return () => ctx.revert();
  }, [currentSlide]);

  return (
    <div className="relative flex items-center md:items-end h-[100svh] min-h-[500px] overflow-hidden bg-[#1f0605] pt-24 pb-16 md:pt-40 md:pb-28">
      {/* Background */}
      <div
        ref={bgRef}
        className="absolute inset-0 bg-cover bg-center transition-all duration-1000"
        style={{
          backgroundImage: `url(${slides[currentSlide].image})`,
        }}
      />

      {/* Overlay */}
      <div className="absolute inset-0 bg-black/50" />

      {/* Content */}
      <div className="relative z-20 w-full px-5 sm:px-8 md:px-20 lg:px-32">
        <div className="max-w-xl mx-auto md:mx-0 text-center md:text-left">
          {/* Title */}
          <h1
            ref={titleRef}
            className="
        text-2xl 
        sm:text-3xl 
        md:text-6xl 
        lg:text-7xl 
        font-semibold 
        leading-snug 
        mb-3 sm:mb-4 md:mb-6
        text-white
      "
          >
            {slides[currentSlide].title}
          </h1>

          {/* Text */}
          <p
            ref={textRef}
            className="
        text-xs 
        sm:text-sm 
        md:text-lg 
        text-gray-200 
        mb-5 sm:mb-6 md:mb-8
        max-w-md 
        mx-auto md:mx-0
        leading-relaxed
      "
          >
            {slides[currentSlide].text}
          </p>

          {/* Button */}
          <div className="flex justify-center md:justify-start">
            <Link to="/contact">
              <Button
                ref={buttonRef}
                className="
            bg-white text-black 
            px-5 sm:px-6 md:px-10 
            py-2 sm:py-2.5 md:py-3 
            rounded-full 
            font-semibold 
            text-xs sm:text-sm md:text-base
            w-auto
          "
              >
                Get in touch
              </Button>
            </Link>
          </div>
        </div>
      </div>

      {/* Indicators */}
      <div className="absolute bottom-6 md:bottom-10 left-1/2 -translate-x-1/2 flex gap-2 md:gap-3 z-30">
        {slides.map((_, index) => (
          <div
            key={index}
            onClick={() => setCurrentSlide(index)}
            className={`h-2 w-6 md:w-8 rounded-full cursor-pointer transition ${
              currentSlide === index ? "bg-white" : "bg-white/40"
            }`}
          />
        ))}
      </div>
    </div>
  );
};

import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import Button from "../ui/button/Button";
import { IconShoppingCart } from "../../assets/icons/interfaceIcons2";

const NAV_LINKS = [
  { label: "About", path: "/abouts" },
  { label: "Service", path: "/services" },
  { label: "Projects", path: "/projects" },
  { label: "Blog", path: "/blog" },
];

export const Navbar = () => {
  const navigate = useNavigate();
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <>
      {/* NAVBAR */}
      <nav
        className={`fixed inset-x-0 top-0 z-50 transition-all duration-500
        ${scrolled ? "bg-white shadow-md" : "bg-transparent backdrop-blur-[50px]"}`}
      >
        <div className="container mx-auto px-4 sm:px-8 h-[70px] flex items-center justify-between">

          {/* LOGO */}
          <Link to="/">
            <h2
              className={`text-2xl md:text-4xl font-extrabold transition
              ${scrolled ? "text-black" : "text-white"}`}
            >
              Homart
            </h2>
          </Link>

          {/* DESKTOP MENU */}
          <ul
            className={`hidden md:flex gap-8 items-center
            ${scrolled ? "text-black" : "text-white"}`}
          >
            {NAV_LINKS.map((item, index) => (
              <li key={index}>
                <Link to={item.path}>{item.label}</Link>
              </li>
            ))}
          </ul>

          {/* RIGHT SIDE (DESKTOP) */}
          <div className="hidden md:flex items-center gap-4">
            <Button className={`${scrolled ? "text-black" : "text-white"}`}>
              <IconShoppingCart size="24" />
            </Button>

            <Button
              onClick={() => navigate("/contact")}
              className={`px-6 rounded-full border ${
                scrolled ? "border-black text-black" : "border-white text-white"
              }`}
            >
              Contact
            </Button>
          </div>

          {/* 🍔 MOBILE MENU BUTTON */}
          <div className="md:hidden">
            <button onClick={() => setMenuOpen(!menuOpen)}>
              <div className="flex flex-col gap-1">
                <span
                  className={`block w-6 h-0.5 transition ${
                    scrolled ? "bg-black" : "bg-white"
                  }`}
                ></span>
                <span
                  className={`block w-6 h-0.5 transition ${
                    scrolled ? "bg-black" : "bg-white"
                  }`}
                ></span>
                <span
                  className={`block w-6 h-0.5 transition ${
                    scrolled ? "bg-black" : "bg-white"
                  }`}
                ></span>
              </div>
            </button>
          </div>

        </div>
      </nav>

      {/* 📱 MOBILE MENU DROPDOWN */}
      <AnimatePresence>
        {menuOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="fixed top-[70px] left-0 w-full bg-white z-40 shadow-md md:hidden"
          >
            <div className="flex flex-col items-center py-6 gap-6">

              {NAV_LINKS.map((item, index) => (
                <Link
                  key={index}
                  to={item.path}
                  onClick={() => setMenuOpen(false)}
                  className="text-lg font-medium"
                >
                  {item.label}
                </Link>
              ))}

              <Button
                onClick={() => {
                  navigate("/contact");
                  setMenuOpen(false);
                }}
                className="px-6 rounded-full border border-black"
              >
                Contact
              </Button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

